    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '22px 28px',
    borderBottom: '1px solid #f3f4f6'
  },
  modalTitle: {
    fontSize: 18,
    fontWeight: 800,
    color: '#111827'
  },
  modalClose: {
    background: '#f3f4f6',
    border: 'none',
    borderRadius: 8,
    width: 32,
    height: 32,
    cursor: 'pointer',
    fontSize: 14,
    color: '#374151'
  },
  modalBody: {
    padding: '24px 28px',
    display: 'flex',
    flexDirection: 'column',
    gap: 14
  },
  modalFooter: {
    display: 'flex',
    gap: 10,
    justifyContent: 'flex-end',
    padding: '18px 28px',
    borderTop: '1px solid #f3f4f6'
  },
  errBox: {
    background: '#fee2e2',
    border: '1px solid #fca5a5',
